function parseCSV(str) {
    var arr = [];
    var quote = false;
    for (var row = 0, col = 0, c = 0; c < str.length; c++) {
        var cc = str[c], nc = str[c+1];
        arr[row] = arr[row] || [];
        arr[row][col] = arr[row][col] || '';

        if (cc == '"' && quote && nc == '"') { arr[row][col] += cc; ++c; continue; }
        if (cc == '"') { quote = !quote; continue; }
        if (cc == ',' && !quote) { ++col; continue; }
        if (cc == '\r' && nc == '\n' && !quote) { ++row; col = 0; ++c; continue; }
        if (cc == '\n' && !quote) { ++row; col = 0; continue; }
        if (cc == '\r' && !quote) { ++row; col = 0; continue; }

        arr[row][col] += cc;
    }
    return arr;
}

function convertColIndexToLetter(index) {
    let letter = '';
    while (index >= 0) {
        let temp = index % 26;
        letter = String.fromCharCode(temp + 65) + letter;
        index = Math.floor(index / 26) - 1;
    }
    return letter;
}

function generate_coach_csv(params) {
    let { csv_raw, apply_formula, sku_column_identifier } = params;

    // Clean markdown code blocks from CSV
    csv_raw = csv_raw.trim().replace(/^\s*```(?:csv)?\s*/i, '').replace(/\s*```\s*$/, '').trim();

    // Attempt to strip out control lines (lines before the first comma separated line)
    // Find the first line that has a comma (outside quotes)
    let lines = csv_raw.split(/\r?\n/);
    let startIdx = 0;
    for (let i = 0; i < lines.length; i++) {
        if (lines[i].includes(',')) {
            startIdx = i;
            break;
        }
    }

    if (startIdx > 0) {
        lines = lines.slice(startIdx);
        csv_raw = lines.join('\n');
    }

    let rows = parseCSV(csv_raw);

    if (apply_formula && rows.length > 0 && sku_column_identifier) {
        let colLetter = "";
        let headerRow = rows[0];

        // Search the header row first
        let colIndex = headerRow.findIndex(h => h && h.trim().toLowerCase() === sku_column_identifier.trim().toLowerCase());

        if (colIndex !== -1) {
            colLetter = convertColIndexToLetter(colIndex);
        } else {
            // If not found in headers, check if it looks like a column letter (A, B, AA, etc.)
            let isLetter = /^[A-Za-z]{1,2}$/.test(sku_column_identifier);
            if (isLetter) {
                colLetter = sku_column_identifier.toUpperCase();
            }
        }

        if (colLetter) {
            rows[0].push("Image Link");
            for (let i = 1; i < rows.length; i++) {
                let cellRef = colLetter + (i + 1);
                // The formula specified: =IMAGE("https://images.coach.com/is/image/Coach/" & LOWER(SUBSTITUTE([CELL], " ", "_")) & "_a0")
                let formula = `=IMAGE("https://images.coach.com/is/image/Coach/" & LOWER(SUBSTITUTE(${cellRef}, " ", "_")) & "_a0")`;
                rows[i].push(formula);
            }
        }
    }

    let outCSV = rows.map(r => r.map(c => {
        let str = c == null ? '' : String(c);
        if (str.includes(',') || str.includes('"') || str.includes('\n') || str.includes('\r')) {
            return '"' + str.replace(/"/g, '""') + '"';
        }
        return str;
    }).join(',')).join('\n');

    // Convert to base64
    // Browser environment uses btoa
    let btoaFunc = typeof btoa !== 'undefined' ? btoa : function(str) { return Buffer.from(str).toString('base64'); };
    // Handle unicode in btoa
    function utf8_to_b64(str) {
      return btoaFunc(unescape(encodeURIComponent(str)));
    }

    let base64CSV = utf8_to_b64(outCSV);
    let dataUri = 'data:text/csv;charset=utf-8;base64,' + base64CSV;

    let html = `
    <div style="padding: 16px; border: 1px solid #e5e7eb; border-radius: 8px; text-align: center; font-family: ui-sans-serif, system-ui, sans-serif; background-color: #f9fafb; color: #111827;">
        <h3 style="margin-top: 0; margin-bottom: 8px; font-weight: 600;">CSV Ready for Download</h3>
        <p style="margin-bottom: 16px; color: #4b5563; font-size: 14px;">The CSV file has been generated successfully.</p>
        <a href="${dataUri}" download="exported_data.csv" style="display: inline-block; padding: 10px 20px; background-color: #3b82f6; color: white; text-decoration: none; border-radius: 6px; font-weight: 500; font-size: 14px; box-shadow: 0 1px 2px 0 rgba(0, 0, 0, 0.05); transition: background-color 0.2s;">
            Download .csv File
        </a>
    </div>
    `;
    return html;
}
